INSERT INTO spells
  (name,level,school,casting_time,range,components,duration,description,higher_levels,classes,ritual,concentration,attack_type,damage_dice,damage_type,save_attribute,source)
VALUES
  ('Explosão de Chamas',0,'Evocação','1 ação','36 metros','V, S','Instantânea','Você lança um fragmento de fogo em direção a uma criatura ou objeto dentro do alcance. Faça uma jogada de ataque com magia à distância. Se acertar, o alvo sofre 1d10 de dano de fogo. O dano aumenta em 1d10 no 5° nível (2d10), 11° nível (3d10) e 17° nível (4d10).',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,'ranged','1d10','Fogo',NULL,'Livro do Jogador'),
  ('Chama Sagrada',0,'Evocação','1 ação','18 metros','V, S','Instantânea','A luz flamejante cai sobre uma criatura que você possa ver dentro do alcance. O alvo deve ser bem-sucedido num teste de resistência de Destreza ou sofrer 1d8 de dano radiante. O alvo não ganha benefício de cobertura. O dano aumenta em 1d8 no 5° (2d8), 11° (3d8) e 17° nível (4d8).',NULL,'{Clérigo}',FALSE,FALSE,NULL,'1d8','Radiante','DEX','Livro do Jogador'),
  ('Toque Gelado',0,'Necromancia','1 ação','36 metros','V, S','1 rodada','Você cria uma mão fantasmagórica na região de uma criatura dentro do alcance. Faça uma jogada de ataque com magia à distância. Se acertar, o alvo sofre 1d8 de dano necrótico e não pode recuperar pontos de vida até o início do seu próximo turno. O dano aumenta em 1d8 no 5° (2d8), 11° (3d8) e 17° nível (4d8).',NULL,'{Feiticeiro,Mago,Warlock}',FALSE,FALSE,'ranged','1d8','Necrótico',NULL,'Livro do Jogador'),
  ('Raio de Gelo',0,'Evocação','1 ação','18 metros','V, S','Instantânea','Um raio de luz azul-branca e fria arremessa em direção a uma criatura dentro do alcance. Faça uma jogada de ataque com magia à distância. Se acertar, o alvo sofre 1d8 de dano frio e sua velocidade é reduzida em 3 metros até o início do seu próximo turno. O dano aumenta em 1d8 no 5° (2d8), 11° (3d8) e 17° nível (4d8).',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,'ranged','1d8','Frio',NULL,'Livro do Jogador'),
  ('Rajada Mística',0,'Evocação','1 ação','36 metros','V, S','Instantânea','Um raio de energia crepitante arremessa em direção a uma criatura dentro do alcance. Faça uma jogada de ataque com magia à distância. Se acertar, o alvo sofre 1d10 de dano de força. Cria dois raios no 5°, três no 11° e quatro no 17° nível.',NULL,'{Warlock}',FALSE,FALSE,'ranged','1d10','Força',NULL,'Livro do Jogador'),
  ('Borrifada de Ácido',0,'Conjuração','1 ação','18 metros','V, S','Instantânea','Você lança uma bolha de ácido em uma ou duas criaturas a até 1,5 metro uma da outra. O alvo deve ser bem-sucedido num teste de resistência de Destreza ou sofrer 1d6 de dano de ácido. O dano aumenta em 1d6 no 5° (2d6), 11° (3d6) e 17° nível (4d6).',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,NULL,'1d6','Ácido','DEX','Livro do Jogador'),
  ('Veneno Nublado',0,'Conjuração','1 ação','3 metros','V, S','Instantânea','Você projeta uma rajada de névoa nociva. A criatura deve ter sucesso num teste de resistência de Constituição ou sofrer 1d12 de dano venenoso. O dano aumenta em 1d12 no 5° (2d12), 11° (3d12) e 17° nível (4d12).',NULL,'{Druida,Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,'1d12','Veneno','CON','Livro do Jogador'),
  ('Dardos Psíquicos',0,'Encantamento','1 ação','18 metros','V','Instantânea','Você lança um fragmento de força psíquica destrutiva. O alvo deve ter sucesso num teste de resistência de Inteligência ou sofrer 1d6 de dano psíquico e subtrair 1d4 de sua próxima rolagem de resistência antes do fim do seu próximo turno. O dano aumenta em 1d6 no 5° (2d6), 11° (3d6) e 17° nível (4d6).',NULL,'{Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,'1d6','Psíquico','INT','Livro do Jogador'),
  ('Golpe de Trovão',0,'Evocação','1 ação','Pessoal (3m raio)','S','Instantânea','Você cria um som de trovão. Cada criatura diferente de você dentro de 1,5 metro deve ser bem-sucedida num teste de resistência de Constituição ou sofrer 1d6 de dano trovejante. O dano aumenta em 1d6 no 5° (2d6), 11° (3d6) e 17° nível (4d6).',NULL,'{Bardo,Druida,Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,'1d6','Trovejante','CON','Livro do Jogador'),
  ('Mãos Mágicas',0,'Conjuração','1 ação','9 metros','V, S','1 minuto','Uma mão espectral e flutuante aparece no ponto que você escolher. Você pode usá-la para manipular objetos, abrir portas ou recipientes destrancados, guardar ou pegar itens. A mão não pode atacar, ativar itens mágicos, ou carregar mais de 4,5 kg.',NULL,'{Bardo,Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Luz',0,'Evocação','1 ação','Toque','V, M (vagalume)','1 hora','Você toca um objeto que emite luz plena em um raio de 6 metros e penumbra por mais 6 metros.',NULL,'{Bardo,Clérigo,Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Ilusão Menor',0,'Ilusão','1 ação','9 metros','S, M (lã de ovelha)','1 minuto','Você cria um som ou imagem de um objeto dentro do alcance que dura pelo tempo de conjuração.',NULL,'{Bardo,Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Resistência',0,'Abjuração','1 ação','Toque','V, S, M (manto em miniatura)','Concentração, até 1 minuto','Você toca uma criatura disposta. Uma vez antes do término da magia, o alvo pode rolar um d4 e adicionar o número a um teste de resistência à sua escolha.',NULL,'{Clérigo,Druida}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Criação de Chamas',0,'Conjuração','1 ação','Pessoal','V, S','10 minutos','Uma chama tremeluzente aparece em sua mão. Você pode arremessá-la a uma criatura dentro de 9 metros como um ataque com magia à distância causando 1d8 de dano de fogo. O dano aumenta em 1d8 no 5° (2d8), 11° (3d8) e 17° nível (4d8).',NULL,'{Druida}',FALSE,FALSE,'ranged','1d8','Fogo',NULL,'Livro do Jogador'),
  ('Mísseis Mágicos',1,'Evocação','1 ação','36 metros','V, S','Instantânea','Você cria três dardos brilhantes de força mágica. Cada dardo atinge uma criatura de sua escolha que você possa ver dentro do alcance. Um dardo causa 1d4+1 de dano de força ao alvo. Os dardos atingem simultaneamente.','Quando conjurado com um espaço de 2° nível ou superior, a magia cria mais um dardo por nível acima do 1°.','{Feiticeiro,Mago}',FALSE,FALSE,NULL,'1d4','Força',NULL,'Livro do Jogador'),
  ('Escudo',1,'Abjuração','1 reação','Pessoal','V, S','1 rodada','Uma barreira invisível de força mágica aparece e protege você. Até o início do seu próximo turno, você tem um bônus de +5 para CA, inclusive contra o ataque que provocou a reação.',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Armadura de Mago',1,'Abjuração','1 ação','Toque','V, S, M (couro curtido)','8 horas','Você toca uma criatura disposta que não está usando armadura. A CA base do alvo torna-se 13 + seu modificador de Destreza.',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Curar Ferimentos',1,'Evocação','1 ação','Toque','V, S','Instantânea','Uma criatura que você toca recupera um número de pontos de vida igual a 1d8 mais seu modificador de habilidade de conjuração. Essa magia não tem efeito em mortos-vivos ou constructos.','Quando conjurado com um espaço de 2° nível ou superior, a cura aumenta em 1d8 para cada nível acima do 1°.','{Bardo,Clérigo,Druida,Paladino,Patrulheiro}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Palavra de Cura',1,'Evocação','1 ação bônus','18 metros','V','Instantânea','Uma criatura de sua escolha que você possa ver dentro do alcance recupera pontos de vida iguais a 1d4 mais seu modificador de habilidade de conjuração.','Quando conjurado com um espaço de 2° nível ou superior, a cura aumenta em 1d4 para cada nível acima do 1°.','{Bardo,Clérigo,Druida}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Dano Sagrado',1,'Necromancia','1 ação','Toque','V, S','Instantânea','Faça um ataque corpo a corpo com magia contra uma criatura que você possa alcançar. Se acertar, o alvo sofre 3d10 de dano necrótico.','Quando conjurado com um espaço de 2° nível ou superior, o dano aumenta em 1d10 para cada nível acima do 1°.','{Clérigo}',FALSE,FALSE,'melee','3d10','Necrótico',NULL,'Livro do Jogador'),
  ('Sono',1,'Encantamento','1 ação','27 metros','V, S, M (areia fina)','1 minuto','Esta magia envia criaturas em sono mágico profundo. Role 5d8; o total é a quantidade de pontos de vida de criaturas que essa magia pode afetar, em ordem crescente de pontos de vida atuais.','Quando conjurado com um espaço de 2° nível ou superior, role um adicional de 2d8 para cada nível acima do 1°.','{Bardo,Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Enfeitiçar Pessoa',1,'Encantamento','1 ação','9 metros','V, S','1 hora','Você tenta enfeitiçar um humanoide que você pode ver dentro do alcance. Ele deve fazer um teste de resistência de Sabedoria. Se falhar, ele é enfeitiçado por você até o término da magia.','Quando conjurado com um espaço de 2° nível ou superior, você pode mirar em mais uma criatura por nível acima do 1°.','{Bardo,Druida,Feiticeiro,Mago,Paladino,Warlock}',FALSE,FALSE,NULL,NULL,NULL,'WIS','Livro do Jogador'),
  ('Detectar Magia',1,'Adivinhação','1 ação','Pessoal','V, S','Concentração, até 10 minutos','Por um tempo de conjuração, você pode sentir a presença de magia dentro de 9 metros de você e ver auras ao redor de objetos ou criaturas mágicas visíveis.',NULL,'{Bardo,Clérigo,Druida,Feiticeiro,Mago,Paladino,Patrulheiro}',TRUE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Disfarçar-se',1,'Ilusão','1 ação','Pessoal','V, S','1 hora','Você faz com que sua aparência física, incluindo roupas, armadura, armas e outros pertences, se pareça diferente até o término da magia.',NULL,'{Bardo,Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Identificação',1,'Adivinhação','1 minuto','Toque','V, S, M (pérola de 100 po, pluma de coruja)','Instantânea','Você aprende as propriedades de um item mágico tocado, como usá-las, se requer atunamento e quantas cargas tem.',NULL,'{Bardo,Mago}',TRUE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Bênção',1,'Encantamento','1 ação','9 metros','V, S, M (água benta)','Concentração, até 1 minuto','Você abençoa até três criaturas de sua escolha dentro do alcance. Sempre que um alvo fizer uma jogada de ataque ou um teste de resistência, o alvo pode rolar um d4 e adicionar ao resultado.','Quando conjurado com um espaço de 2° nível ou superior, você pode mirar em mais uma criatura por nível acima do 1°.','{Clérigo,Paladino}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Raio de Gelo (1°)',1,'Conjuração','1 ação','18 metros','S, M (gelo ou água)','Instantânea','Você lança um fragmento de gelo como projétil. Faça um ataque com magia à distância. Se acertar, 1d10 de dano penetrante, depois o gelo explode: criaturas a 1,5m fazem TR de Destreza ou sofrem 2d6 de dano frio.','Quando conjurado com um espaço de 2° nível ou superior, o dano de frio aumenta em 1d6 para cada nível acima do 1°.','{Druida,Feiticeiro,Mago}',FALSE,FALSE,'ranged','1d10','Penetrante','DEX','Livro do Jogador'),
  ('Relâmpago de Bruxa',1,'Evocação','1 ação','9 metros','V, S, M (galho de árvore atingida por raio)','Concentração, até 1 minuto','Um raio de energia elétrica forma um fio entre você e o alvo. Faça uma jogada de ataque com magia à distância. Se acertar, 1d12 de dano elétrico; em turnos seguintes, como ação, 1d12 automaticamente.','Quando conjurado com um espaço de 2° nível ou superior, o dano inicial aumenta em 1d12 por nível acima do 1°.','{Feiticeiro,Mago,Warlock}',FALSE,TRUE,'ranged','1d12','Elétrico',NULL,'Livro do Jogador'),
  ('Passo Místico',2,'Conjuração','1 ação bônus','Pessoal','V','Instantânea','Brevemente envolto em neblina prateada, você se teleporta até 9 metros para um espaço desocupado que você possa ver.',NULL,'{Feiticeiro,Mago,Paladino,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Invisibilidade',2,'Ilusão','1 ação','Toque','V, S, M (cílio envolto em resina de goma)','Concentração, até 1 hora','Uma criatura que você toca torna-se invisível até o término da magia. A magia termina para um alvo que atacar ou lançar uma magia.','Quando conjurado com um espaço de 3° nível ou superior, você pode mirar em mais uma criatura por nível acima do 2°.','{Bardo,Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Teia',2,'Conjuração','1 ação','18 metros','V, S, M (teia de aranha)','Concentração, até 1 hora','Você conjura uma massa de teia espessa e grudenta. Criaturas que entrem na área fazem TR de Destreza ou ficam impedidas.',NULL,'{Feiticeiro,Mago}',FALSE,TRUE,NULL,NULL,NULL,'DEX','Livro do Jogador'),
  ('Raio Ardente',2,'Evocação','1 ação','36 metros','V, S','Instantânea','Você cria três raios de fogo e os arremessa para alvos dentro do alcance. Para cada raio, faça uma jogada de ataque com magia à distância. Se acertar, o alvo sofre 2d6 de dano de fogo.','Quando conjurado com um espaço de 3° nível ou superior, você cria mais um raio adicional para cada nível acima do 2°.','{Feiticeiro,Mago}',FALSE,FALSE,'ranged','2d6','Fogo',NULL,'Livro do Jogador'),
  ('Imobilizar Pessoa',2,'Encantamento','1 ação','18 metros','V, S, M (pedaço de ferro)','Concentração, até 1 minuto','Escolha um humanoide que você possa ver dentro do alcance. O alvo deve ter sucesso em um teste de resistência de Sabedoria ou ficar paralisado.','Quando conjurado com um espaço de 3° nível ou superior, você pode mirar em mais um humanoide por nível acima do 2°.','{Bardo,Clérigo,Druida,Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,'WIS','Livro do Jogador'),
  ('Restauração Menor',2,'Abjuração','1 ação','Toque','V, S','Instantânea','Você toca uma criatura e pode encerrar uma doença ou uma condição que a aflige. A condição pode ser cego, surdo, paralisado ou envenenado.',NULL,'{Bardo,Clérigo,Druida,Paladino,Patrulheiro}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Escuridão',2,'Evocação','1 ação','18 metros','V, M (pelo de morcego e breu)','Concentração, até 10 minutos','A escuridão mágica se espalha de um ponto que você escolher dentro do alcance, preenchendo uma esfera com raio de 4,5 metros. Essa escuridão contorna cantos.',NULL,'{Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Bola de Fogo',3,'Evocação','1 ação','45 metros','V, S, M (guano de morcego e enxofre)','Instantânea','Uma faísca brilhante explode em um estrondo de chamas em uma esfera de 6 metros de raio. Cada criatura na área deve fazer TR de Destreza. O alvo sofre 8d6 de dano de fogo se falhar, ou metade se for bem-sucedido.','Quando conjurado com um espaço de 4° nível ou superior, o dano aumenta em 1d6 para cada nível acima do 3°.','{Feiticeiro,Mago}',FALSE,FALSE,NULL,'8d6','Fogo','DEX','Livro do Jogador'),
  ('Raio',3,'Evocação','1 ação','Pessoal (30m de linha)','V, S, M (cristal de quartzo)','Instantânea','Um raio de eletricidade de 1,5 metro de largura irrompe de você em uma linha de 30 metros. Cada criatura na linha deve fazer TR de Destreza. Sofre 8d6 de dano elétrico se falhar, ou metade se for bem-sucedida.','Quando conjurado com um espaço de 4° nível ou superior, o dano aumenta em 1d6 para cada nível acima do 3°.','{Feiticeiro,Mago}',FALSE,FALSE,NULL,'8d6','Elétrico','DEX','Livro do Jogador'),
  ('Voo',3,'Transmutação','1 ação','Toque','V, S, M (pluma de ave)','Concentração, até 10 minutos','Você toca uma criatura disposta. O alvo ganha uma velocidade de voo de 18 metros pelo tempo de conjuração.','Quando conjurado com um espaço de 4° nível ou superior, você pode mirar em mais uma criatura por nível acima do 3°.','{Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Contramágica',3,'Abjuração','1 reação','18 metros','S','Instantânea','Você tenta interromper uma criatura no processo de lançar uma magia. Magias de 3° nível ou inferior falham automaticamente. Para magias superiores, faça uma verificação usando sua habilidade de conjuração (CD 10 + nível da magia).','Quando conjurado com um espaço de 4° nível ou superior, a magia interrompida não tem efeito se seu nível for menor ou igual ao do espaço usado.','{Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Dissipar Magia',3,'Abjuração','1 ação','36 metros','V, S','Instantânea','Escolha uma criatura, objeto ou efeito mágico. Qualquer magia de 3° nível ou inferior no alvo termina. Para magias superiores, faça uma verificação de habilidade (CD 10 + nível da magia).','Quando conjurado com um espaço de 4° nível ou superior, você encerra automaticamente magias com nível igual ou inferior ao espaço usado.','{Bardo,Clérigo,Druida,Feiticeiro,Mago,Paladino,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Reviver',3,'Necromancia','1 ação','Toque','V, S, M (diamantes de 300 po)','Instantânea','Você toca uma criatura que morreu no último minuto. Essa criatura volta à vida com 1 ponto de vida.',NULL,'{Clérigo,Paladino}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Guardiões Espirituais',3,'Conjuração','1 ação','Pessoal (4,5m de raio)','V, S, M (símbolo sagrado)','Concentração, até 10 minutos','Você chama espíritos para protegê-lo em 4,5 metros. Criaturas que entrem na área fazem TR de Sabedoria. Com falha, sofrem 3d8 de dano radiante (ou necrótico se você for mal).','Quando conjurado com um espaço de 4° nível ou superior, o dano aumenta em 1d8 por nível acima do 3°.','{Clérigo}',FALSE,TRUE,NULL,'3d8','Radiante','WIS','Livro do Jogador'),
  ('Nuvem Pútrida',3,'Conjuração','1 ação','27 metros','V, S, M (ovo podre)','Concentração, até 1 minuto','Você cria uma nuvem de gás amarelo-esverdeado de 6 metros de raio. Criaturas completamente dentro da nuvem fazem TR de Constituição no início de seu turno. Com falha, ficam incapacitadas e vomitando.',NULL,'{Bardo,Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,'CON','Livro do Jogador'),
  ('Banimento',4,'Abjuração','1 ação','18 metros','V, S, M (objeto repugnante à criatura)','Concentração, até 1 minuto','Você tenta enviar uma criatura dentro do alcance para outro lugar. O alvo deve ter sucesso num teste de resistência de Carisma ou ser banido.','Quando conjurado com um espaço de 5° nível ou superior, você pode mirar em mais uma criatura por nível acima do 4°.','{Clérigo,Feiticeiro,Mago,Paladino,Warlock}',FALSE,TRUE,NULL,NULL,NULL,'CHA','Livro do Jogador'),
  ('Invisibilidade Maior',4,'Ilusão','1 ação','Toque','V, S','Concentração, até 1 minuto','Você ou uma criatura que você toca torna-se invisível até o término da magia. A magia não termina quando o alvo atacar ou lançar uma magia.',NULL,'{Bardo,Feiticeiro,Mago}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Porta Dimensional',4,'Conjuração','1 ação','150 metros','V','Instantânea','Você se teleporta de seu local atual para qualquer local dentro do alcance. Você pode trazer um objeto até 450 kg ou uma criatura Média ou menor que esteja ao alcance de uma mão.',NULL,'{Bardo,Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Coluna de Chamas',5,'Evocação','1 ação','18 metros','V, S, M (enxofre)','Instantânea','Uma coluna vertical de fogo divino desce sobre um ponto. Cada criatura em um cilindro de 3 metros de raio e 12 metros de altura deve fazer TR de Destreza. Com falha, sofre 4d6 de dano de fogo e 4d6 de dano radiante.','Quando conjurado com um espaço de 6° nível ou superior, o dano de fogo ou dano radiante aumenta em 1d6 por nível acima do 5°.','{Clérigo}',FALSE,FALSE,NULL,'4d6','Fogo','DEX','Livro do Jogador'),
  ('Imobilizar Monstro',5,'Encantamento','1 ação','27 metros','V, S, M (pedaço de ferro)','Concentração, até 1 minuto','Escolha uma criatura que você possa ver dentro do alcance. O alvo deve ter sucesso em um teste de resistência de Sabedoria ou ficar paralisado. Não tem efeito em mortos-vivos.','Quando conjurado com um espaço de 6° nível ou superior, você pode mirar em mais uma criatura por nível acima do 5°.','{Bardo,Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,'WIS','Livro do Jogador'),
  ('Raio de Enfraquecimento',5,'Necromancia','1 ação','18 metros','V, S','Concentração, até 1 minuto','Um fio de energia negra se lança de seu dedo. Faça uma jogada de ataque com magia à distância. Se acertar, o alvo sofre 4d8 de dano necrótico e você recupera pontos de vida iguais à metade do dano.','Quando conjurado com um espaço de 6° nível ou superior, o dano aumenta em 1d8 por nível acima do 5°.','{Feiticeiro,Mago,Warlock}',FALSE,TRUE,'ranged','4d8','Necrótico',NULL,'Livro do Jogador'),
  ('Curar Ferimentos em Massa',5,'Conjuração','1 ação','18 metros','V, S','Instantânea','Uma onda de energia curativa varre de um ponto que você escolher. Escolha até seis criaturas em uma esfera de 9 metros. Cada alvo recupera 3d8 + modificador de conjuração em PV.','Quando conjurado com um espaço de 6° nível ou superior, a cura aumenta em 1d8 por nível acima do 5°.','{Clérigo,Druida}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Carne para Pedra',6,'Transmutação','1 ação','18 metros','V, S, M (cal, terra e água)','Concentração, até 1 minuto','Você tenta transformar uma criatura dentro do alcance em pedra. O alvo deve fazer um teste de resistência de Constituição.',NULL,'{Feiticeiro,Mago,Warlock}',FALSE,TRUE,NULL,NULL,NULL,'CON','Livro do Jogador'),
  ('Círculo da Morte',6,'Necromancia','1 ação','45 metros','V, S, M (pó de osso pulverizado)','Instantânea','Uma esfera de energia negativa irradia de um ponto. Cada criatura em uma esfera de 18 metros de raio deve fazer TR de Constituição. Com falha, sofre 8d6 de dano necrótico; metade em caso de sucesso.','Quando conjurado com um espaço de 7° nível ou superior, o dano aumenta em 2d6 por nível acima do 6°.','{Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,'8d6','Necrótico','CON','Livro do Jogador'),
  ('Dedo da Morte',7,'Necromancia','1 ação','18 metros','V, S','Instantânea','Você envia energia negativa em direção a uma criatura. O alvo deve fazer um teste de resistência de Constituição. Com falha, sofre 7d8+30 de dano necrótico; metade em caso de sucesso.',NULL,'{Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,'7d8','Necrótico','CON','Livro do Jogador'),
  ('Teleporte',7,'Conjuração','1 ação','3 metros','V','Instantânea','Esta magia teleporta instantaneamente você e até oito criaturas dispostas de sua escolha para um destino que você especificar.',NULL,'{Bardo,Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Campo Antimagia',8,'Abjuração','1 ação','Pessoal (3m raio)','V, S, M (pó de ferro e vidro)','Concentração, até 1 hora','Uma esfera invisível de antimagia de 3 metros de raio se expande de você. Dentro da esfera, as magias não podem ser lançadas e itens mágicos se tornam não mágicos.',NULL,'{Clérigo,Mago}',FALSE,TRUE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Terremoto',8,'Evocação','1 ação','150 metros','V, S, M (terra e rocha)','Concentração, até 1 minuto','Você cria um tremor sísmico em um ponto do solo dentro do alcance. Um abalo intenso agita o solo em uma área de 30 metros de raio.',NULL,'{Clérigo,Druida,Feiticeiro}',FALSE,TRUE,NULL,NULL,NULL,'CON','Livro do Jogador'),
  ('Palavra de Poder Matar',9,'Encantamento','1 ação','18 metros','V','Instantânea','Você pronuncia uma palavra de poder que compele uma criatura dentro do alcance a morrer instantaneamente. Se a criatura tiver 100 pontos de vida ou menos, ela morre.',NULL,'{Bardo,Feiticeiro,Mago,Warlock}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Desejo',9,'Conjuração','1 ação','Pessoal','V','Instantânea','Desejo é a magia mais poderosa disponível para mortais. Simplesmente ao falar em voz alta, você pode alterar os fundamentos da realidade. O uso mais básico é duplicar qualquer outra magia de 8° nível ou inferior.',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador'),
  ('Parar o Tempo',9,'Transmutação','1 ação','Pessoal','V','Instantânea','Você brevemente para o fluxo do tempo para todos, exceto você. Você toma 1d4+1 turnos seguidos. A magia termina se uma de suas ações afetar outra criatura.',NULL,'{Feiticeiro,Mago}',FALSE,FALSE,NULL,NULL,NULL,NULL,'Livro do Jogador');